const trigger = $('Telegram Trigger').first().json;
const mensaje = (trigger.message.text || '').trim();
const chat_id = String(trigger.message.chat.id);
const telegram_user = String(trigger.message.from.id);
const sesion = $('Leer Sesiones').first().json || {};
let estado = (sesion.pantalla_actual || 'MENU').trim().toUpperCase();
