// ============================================================
// NODO CENTRAL: reconstruye el contexto desde los nodos
// productores (los nodos Code/Sheets de cada rama),
// guarda la sesion en Sheets y pasa chat_id+respuesta adelante.
// Necesario porque los nodos Sheets no propagan JSON previo.
// ============================================================

const PRODUCTORES = [
  'Mostrar ayuda',
  'Opcion invalida menu',
  'Iniciar creacion de solicitud',
  'Iniciar consulta por ID',
  'Formatear mis tickets',
  'Formatear reporte',
  'Evaluar perfil',
  'Iniciar cambio de estado',
  'Salir de config',
  'Opcion invalida config',
  'Guardar ID ticket para estado',
  'Preparar nuevo estado',
  'Cancelar cambio estado',
  'Estado invalido',
  'Guardar tipo seleccionado',
  'Cancelar y limpiar sesion',
  'Tipo invalido',
  'Guardar prioridad',
  'Guardar descripcion',
  'Verificar confirmacion',
  'Formatear consulta'
];

const ctx = $('Preparar contexto').item.json;
const chat_id = String(ctx.chat_id);
const telegram_user = String(ctx.telegram_user);

let estado = 'MENU';
let datos = {};
let respuesta = '';

for (const nombre of PRODUCTORES) {
  try {
    const j = $(nombre).item.json;
    if (j && j.respuesta) {
      respuesta = j.respuesta;
      estado    = j.estado    || 'MENU';
      datos     = j.datos     || {};
      break;
    }
  } catch(e) {}
}

if (!respuesta) {
  throw new Error('No se encontro respuesta en ningun nodo productor');
}

// Guardar sesion en Sheets via HTTP interno no es posible aqui,
// pero si pasamos los valores correctos el nodo Sheets que sigue los usara.
return [{ json: {
  chat_id,
  telegram_user,
  estado,
  datos_temp: JSON.stringify(datos),
  respuesta
} }];
